@startuml
skinparam backgroundColor #AAAADD
skinparam packageBackgroundColor #AAAADD

package "Bean" {

class lable {
  int ID
  String info
}

class borrowHis {
  Date returnDate
  Boolean flag
}

class user {
  String ID
  String pwd
  Date createTime
  byte status
}

class ticket {
  String title
  String info
  String adminID
}

class bookDetList {
  String ID
  Date borrowDate
  short deadline
  byte status
}

class borrower {
  String firstName
  String lastName
  String IDCardNo
  String email
  String m_phoneNumber
  String creditRating
}

class root {
}

class admin {
  String firstName
  String lastName
  String email
  Boolean root
}

class bookDetListInfo {
  byte number
}

class book {
  String ISBN
  String name
  String Label
  String logo
  String info
  float price
  String publisher
  String author
  Date publishDate
  short stock
  short Number
}

note "图书分类,用来控制添加或修改图书时\n控制器选项范围,不与book建立直接联系" as N1

lable .. N1

user "1" --> "N" ticket : 拥有或管理
ticket "N" --> "包含" bookDetList : 包含
borrowHis <|-- bookDetList : 继承
user <|-- borrower : 继承
user <|-- root : 继承
user <|-- admin : 继承
ticket "N" --> "1" admin : 管理
bookDetList "1" --> "1" bookDetListInfo : 拥有
bookDetListInfo "1" --> "1" book : 记录

}

@enduml
